                        if (expression[i] == '+') {
                            res.push_back(l + r);
                        } else if (expression[i] == '-') {
                            res.push_back(l - r);
                        } else {
                            res.push_back(l * r);
                        }
                    }
                }
            }
        }
        return res;
    }
};
